package org.apache.camel.component.fix;

import org.apache.camel.Processor;
import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX Consumer to receive FIX protocol messages
 */
public class FixConsumer extends DefaultConsumer {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private final FixEndpoint endpoint;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
        this.endpoint = endpoint;
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();

        FixConfiguration config = endpoint.getConfiguration();

        if (LOG.isDebugEnabled()) {
            LOG.debug("Starting FIX Consumer: sessionID={}, senderCompID={}, targetCompID={}, version={}",
                    endpoint.getSessionID(), config.getSenderCompID(), config.getTargetCompID(), config.getFixVersion());
        }

        // Initialize FIX session/acceptor
        // This would typically establish a connection or set up a listener
    }

    @Override
    protected void doStop() throws Exception {
        if (LOG.isDebugEnabled()) {
            LOG.debug("Stopping FIX Consumer: sessionID={}", endpoint.getSessionID());
        }

        // Clean up FIX session/acceptor
        // This would typically close connections or clean up resources

        super.doStop();
    }
}

